import csv
from collections import defaultdict


def process_pipeline():
    dept_data = defaultdict(list)

    try:
        with open("input.csv", mode="r", newline="", encoding="utf-8") as infile:
            reader = csv.DictReader(infile)
            for row in reader:
                if row["status"] == "active":
                    dept = row["department"]
                    salary = float(row["salary"])
                    dept_data[dept].append(salary)
    except FileNotFoundError:
        return

    results = []
    for dept, salaries in dept_data.items():
        avg_salary = round(sum(salaries) / len(salaries), 2)
        results.append(
            {
                "department": dept,
                "avg_salary": f"{avg_salary:.2f}",
                "count": len(salaries),
            }
        )

    results.sort(key=lambda x: x["department"])

    with open("output.csv", mode="w", newline="", encoding="utf-8") as outfile:
        fieldnames = ["department", "avg_salary", "count"]
        writer = csv.DictWriter(outfile, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(results)


if __name__ == "__main__":
    process_pipeline()
